scripts.script:
// Deterministic daily market data: a fluctuation % and the quarter it fell in.
function marketData() {
  var quarters = ['Q1', 'Q2', 'Q3', 'Q4']
  var out = []
  for (var i = 0; i < 92; i++) {
    var pct =
      3.2 * Math.sin(i / 4.0) + 1.4 * Math.sin(i / 1.3) + 0.5 * Math.cos(i / 2.7)
    out.push({
      day: i,
      pct: Math.round(pct * 100) / 100,
      q: quarters[Math.floor(i / 23) % 4],
    })
  }
  return out
}

// Register the shared records BEFORE the charts are constructed.
ApexCharts.crossfilter({ id: 'market', records: marketData() })

vanilla-js-script:
// charts[0] = fluctuation histogram (brush source), charts[1] = byQuarter.
var cf = ApexCharts.getCrossfilter('market')
var readout = document.getElementById('cf-readout')

if (cf) {
  cf.on('change', function (state) {
    var r = state.filters.fluctuation
    if (r) {
      readout.textContent =
        'Fluctuation ' + r[0].toFixed(2) + '% to ' + r[1].toFixed(2) +
        '%   ->   ' + state.filteredCount + ' / ' + state.total + ' days'
    } else {
      readout.textContent = 'No filter (all ' + state.total + ' days)'
    }
  })
}

document.getElementById('cf-reset').addEventListener('click', function () {
  if (cf) cf.reset()
})
